#include <iostream>
using namespace std;

int main() {
    int hp, mana;
    cout << "Введіть HP гравця та ману (через пробіл): ";
    cin >> hp >> mana;

    // Вкладені умови та використання && (Декілька умов одночасно)
    if (hp <= 0) {
        cout << "Гру закінчено. Ви загинули." << endl;
    } 
    else if (hp < 20 && mana >= 50) {
        cout << "ХП критично мало, але є мана! Використовуємо 'Лікування'!" << endl;
    } 
    else if (hp < 20 && mana < 50) {
        cout << "Тікайте! Мало ХП і немає мани." << endl;
    } 
    else {
        cout << "Можна продовжувати бій." << endl;
    }

    // Демонстрація тернарного оператора
    int damage = (hp > 50) ? 20 : 5;
    cout << "Ваш поточний урон: " << damage << endl;

    return 0;
}
